Here's how to test `DataFetcher` with proper timeout/cancellation handling in MSTest:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_NonSuccessStatus_ThrowsHttpRequestException()
    {
        var handler = new FakeHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        var handler = new FakeHttpMessageHandler("data", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // MSTest enforces this via TestContext.CancellationToken
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new FakeHttpMessageHandler("fast", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Pass TestContext.CancellationToken so the [Timeout] is cooperative
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    // Reusable fake handler — avoids mocking frameworks
    private sealed class FakeHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public FakeHttpMessageHandler(string content, HttpStatusCode statusCode,
            TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Cooperative timeout** | `[Timeout(5000)]` + pass `_testContext.CancellationToken` into the async call |
| **Cancellation** | Create a pre-cancelled `CancellationTokenSource`, assert `TaskCanceledException` |
| **Exception testing** | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |
| **HttpClient testing** | Custom `HttpMessageHandler` — no mocking library needed |
| **Class is `sealed`** | Performance + design clarity |
| **Constructor injection** | `TestContext` injected via constructor (MSTest 3.6+), enabling `readonly` |

The critical detail: **`[Timeout]` only works cooperatively** — if you don't pass `TestContext.CancellationToken` to your async calls, MSTest can't actually cancel the operation when time runs out.
